#include <iostream>
#include <vector>

using namespace std;

class MaxHeap
{
private:
    vector<int> data;

    void siftUp(int i)
    {
        while (i > 0 && data[(i - 1) / 2] < data[i])
        {
            swap(data[(i - 1) / 2], data[i]); // parent is smaller — swap up
            i = (i - 1) / 2;
        }
    }

public:
    void insert(int value)
    {
        data.push_back(value); // add at the end
        siftUp(data.size() - 1); // restore the heap property
    }

    int top()
    {
        return data[0]; // the max is ALWAYS at the root
    }
};

int main()
{
    MaxHeap heap;
    heap.insert(5);
    heap.insert(10);
    heap.insert(3);
    heap.insert(8);

    cout << heap.top() << endl;

    return 0;
}

